import stylesText from './activity-card.css?inline';
import { cssStyleSheet } from '../../../../utils/css.js';
import { HealthService } from '../../../../services/health.service.js';
import { activityIcon } from '../../health-utils.js';
import { createComponentLogger } from '../../../../utils/component-logger.js';

const styles = cssStyleSheet(stylesText);
import type { Activity } from '@motivation/shared';

const template = document.createElement('template');
template.innerHTML = `
    <div class="activity-card" id="activity-card"></div>
    <pre class="screen-error" hidden></pre>
`;

export class ActivityCard extends HTMLElement {
    static readonly observedAttributes = ['date'];
    private readonly log = createComponentLogger('activity-card');
    private loadSequence = 0;
    /** Resolves when the most recent load() call finishes — exposed for tests and external awaits. */
    loadPromise: Promise<void> = Promise.resolve();

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    attributeChangedCallback(name: string, _oldValue: string | null, newValue: string | null): void {
        if (name === 'date' && newValue) {
            this.load(newValue);
        }
    }

    load(date: string): Promise<void> {
        const currentLoad = ++this.loadSequence;
        this.loadPromise = (async () => {
            try {
                const activities = await HealthService.fetchActivitiesByDate(date);
                if (currentLoad !== this.loadSequence) return;
                this.render(activities);
            } catch (err) {
                if (currentLoad !== this.loadSequence) return;
                this.log.error('Failed to load activities for', date, err);
                this.setError(err);
            }
        })();
        return this.loadPromise;
    }

    private formatDuration(minutes?: number): string {
        if (!minutes) return '';
        if (minutes >= 60) {
            const h = Math.floor(minutes / 60);
            const m = minutes % 60;
            return m > 0 ? `${h}h${m}m` : `${h}h`;
        }
        return `${minutes}m`;
    }

    private render(activities: Activity[]): void {
        const shadow = this.shadowRoot!;
        const container = shadow.getElementById('activity-card')!;
        container.replaceChildren();
        shadow.querySelector<HTMLElement>('.screen-error')!.hidden = true;
        this.hidden = activities.length === 0;

        for (const activity of activities) {
            const chip = document.createElement('div');
            chip.className = 'activity-chip';

            const icon = document.createElement('span');
            icon.className = 'chip-icon';
            icon.textContent = activityIcon(activity.type);
            chip.appendChild(icon);

            const dur = this.formatDuration(activity.duration_minutes);
            if (dur) {
                const durEl = document.createElement('span');
                durEl.className = 'chip-duration';
                durEl.textContent = dur;
                chip.appendChild(durEl);
            }

            container.appendChild(chip);
        }
    }

    private setError(err: unknown): void {
        const shadow = this.shadowRoot!;
        this.hidden = false;
        shadow.getElementById('activity-card')!.replaceChildren();
        const errorEl = shadow.querySelector<HTMLElement>('.screen-error')!;
        errorEl.textContent = err instanceof Error ? (err.stack ?? err.message) : String(err);
        errorEl.hidden = false;
    }
}

customElements.define('activity-card', ActivityCard);
